import React from "react";

const WeatherCard = ({
  city,
  temperature,
  condition,
  wind,
  humidity,
  aqi
}) => {
  // ✅ Safe AQI conversion (no unused vars)
  const aqiValue = aqi ? Number(aqi) : null;

  // 🌫 AQI label + color system
  const getAQIInfo = (value) => {
    if (value === 1) return { label: "Good", color: "#16a34a" };
    if (value === 2) return { label: "Moderate", color: "#eab308" };
    if (value === 3) return { label: "Unhealthy", color: "#ef4444" };
    return { label: "Unknown", color: "#6b7280" };
  };

  const aqiInfo = getAQIInfo(aqiValue);

  return (
    <div className="card">
      {/* CITY */}
      <h2 className="city">{city}</h2>

      {/* CONDITION */}
      <p className="condition">{condition}</p>

      {/* TEMP */}
      <div className="temp">{temperature}°C</div>

      {/* STATS */}
      <div className="stats">

        <div className="stat-item">
          <span>🌬 Wind</span>
          <span>{wind} km/h</span>
        </div>

        <div className="stat-item">
          <span>💧 Humidity</span>
          <span>{humidity}%</span>
        </div>

        <div className="stat-item">
          <span>🌫 AQI</span>
          <span style={{ color: aqiInfo.color, fontWeight: 600 }}>
            {aqiInfo.label}
          </span>
        </div>

      </div>
    </div>
  );
};

export default WeatherCard;
